init_eqs:
i=0; loop (5000,i[0]=0; gmem[i]=0; i+=1;);
octaves=3; minbpm=75; maxbpm=200; nres_oct=60;
nres_extra=nres_oct/log(2)*log(maxbpm/minbpm/2);
nres=nres_oct*octaves+nres_extra;
bstep = log(2)/nres_oct;
nres_out = ceil(nres_oct+nres_extra); //int is necessary !

maxind = 40;
i=0;
loop (nres,
//precalculate BPM
(8*i)[3]=minbpm*exp(i*bstep);
//precalculate weighting
if (i<=nres_out,(8*i)[4]=min(2,1+sin($pi*i/nres_out)*3)/2,0);;
i+=1);

BPMScrollTime = 0;

rand1_neg = int(rand(2));
rand2_neg = int(rand(2));

rand1_neg_nextrow = int(rand(2));
rand2_neg_nextrow = int(rand(2));

rand1 = if(rand1_neg, rand(1)/5, -(rand(1)/2));
rand2 = if(rand2_neg, rand(1)/5, -(rand(1)/2));

rand1_nextrow = if(rand1_neg_nextrow, rand(1)*25, -(rand(1)*25));
rand2_nextrow = if(rand2_neg_nextrow, rand(1)*25, -(rand(1)*25));

frame_eqs:
//martin/Nitorami - DFT based BPM identification

dt=1/fps;
tcorr = (dt - dt_); //to compensate timing errors caused by MD's time smoothing
dt_= dt;
treal += dt + tcorr*38; //I-share of timing error comp.
exc=2*bass+mid+treb;  //choose what you like but mind this could affect quali
d0= exp(-1.5*dt);
i=0; avg = 0;
loop (nres,
n = 8*i;
w = 2*$pi/60*n[3];
d = 1-dt*w*0.013; //DFT smoothing optimised for nres_oct=60
arg = treal*w + tcorr*15000; //P-share of timing error comp.
n[1] = n[1]*d +exc*cos(arg)*(1-d); //DFT real part
n[2] = n[2]*d +exc*sin(arg)*(1-d); //DFT imaginary part
if (i<nres_out,
n2 = 8*(i+nres_oct);
n4 = 8*(i+nres_oct*2);
sum = sqrt (sqr(n[1])+sqr(n[2]) + sqr(n2[1])+sqr(n2[2]) + sqr(n4[1])+sqr(n4[2]));
avg += sum;
n[0]= n[0]*d0+sum*(1-d0)*n[4];
if (n[0]>(8*promax)[0], promax=max(2,min(nres_out-2,i));,0);
,0);
i += 1;);
avg_ = avg_*d0 + (1-d0)*avg/nres_out;

//Resist frequent BPM changes
m8 = 8*maxind;
wait += abs(m8[0]-(8*promax)[0])*dt*100;
if (wait>abs(promax-maxind)*80/nres_oct, maxind=promax; wait = 0,0);

//OUTPUT
BPM = m8[3];

//Se7enSlasher - Convert BPM to integer and do a simple rounding.
//intBPM = floor(BPM+.5); //More efficient way?
intBPM = int(BPM);

q1 = intBPM;
monitor = q1;

time_sync += ((1/fps) * (q1/30))/2;
time_sync = if (time_sync >= 2, 0, time_sync);

//martin (Nitorami)
t1 += q1/60*$PI*dt;

bpmMod = if(time_sync >= 0 && time_sync <= 1, 0, 1);

//martin (Nitorami)
jump1 = max(0, sin(t1));
jump2 = max(0, sin(t1+$PI));

jump1 = if(timeUntilStop <= 0, 0, jump1);
jump2 = if(timeUntilStop <= 0, 0, jump2);

//Used for smooth landing when it's no music
dec= exp(-30/fps);
jump1_=dec*jump1_+(1-dec)*jump1;
jump2_=dec*jump2_+(1-dec)*jump2;


//Se7enSlasher - Timed Stop Technique
//Change the t1 value to 0 when there is no sound.
timeUntilStop = if (bass+mid+treb > 0, .5, timeUntilStop);
timeUntilStop -= 1/fps;
t1 = if(timeUntilStop <= 0, 0, t1);

q31 = if(timeUntilStop <= 0, jump1_, jump1);
q32 = if(timeUntilStop <= 0, jump2_, jump2);

monitor = t1;

wave_a = 0;
decay = 0;

BPMScrollTime += smooth_BPM*.0001;
q5 = BPMScrollTime;

decscroll = 1/fps;
smooth_BPM = smooth_BPM * (1-decscroll) + q1 * decscroll;

monitor = q1;

q6 = rand1;
q7 = rand2;
q8 = rand1_nextrow;
q9 = rand2_nextrow;
